#[test]
fn modified_amino_acids_stay_in_protein_chain() {
    let mut rows = ala_rows("A", 0.0);
    // Replace ALA at seq 2..4 with SEP, MSE, PTR.
    let names = ["SEP", "MSE", "PTR"];
    for (i, name) in names.iter().enumerate() {
        for r in ala_rows("A", (i as f64 + 1.0) * 4.0) {
            rows.push(AtomSite {
                label_comp_id: name,
                label_seq_id: (i as i32) + 2,
                ..r
            });
        }
    }
    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_protein_category(),
        atom_site_category(&rows, &AtomSiteOpts::default()),
    ]);
    let entities = bcif_to_entities(&bcif).unwrap();
    let protein = first_protein(&entities).as_protein().unwrap();
    assert_eq!(protein.residues.len(), 4);
    let names: Vec<String> = protein
        .residues
        .iter()
        .map(|r| std::str::from_utf8(&r.name).unwrap().trim().to_owned())
        .collect();
    assert!(names.contains(&"SEP".to_owned()));
    assert!(names.contains(&"MSE".to_owned()));
    assert!(names.contains(&"PTR".to_owned()));
}

#[test]
fn modified_nucleotides_classify_as_rna() {
    fn na_atom(
        name: &'static str,
        elem: &'static str,
        comp: &'static str,
        seq: i32,
        x: f64,
    ) -> AtomSite {
        AtomSite {
            label_atom_id: name,
            label_comp_id: comp,
            label_asym_id: "A",
            label_seq_id: seq,
            label_entity_id: "1",
            x,
            y: 0.0,
            z: 0.0,
            occupancy: 1.0,
            b_factor: 10.0,
            type_symbol: elem,
            model: 1,
            label_alt_id: None,
            auth_asym_id: None,
            auth_seq_id: None,
            auth_comp_id: None,
            auth_atom_id: None,
            ins_code: None,
            formal_charge: None,
        }
    }
    let mut rows = Vec::new();
    let names = ["A", "PSU", "5MU"];
    let backbone = [
        ("P", "P"),
        ("O5'", "O"),
        ("C5'", "C"),
        ("C4'", "C"),
        ("C3'", "C"),
        ("O3'", "O"),
    ];
    for (i, name) in names.iter().enumerate() {
        let base_x = (i as f64) * 8.0;
        for (j, (atom, elem)) in backbone.iter().enumerate() {
            rows.push(na_atom(
                atom,
                elem,
                name,
                (i as i32) + 1,
                base_x + (j as f64) * 1.5,
            ));
        }
    }
    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_rna_category(),
        atom_site_category(&rows, &AtomSiteOpts::default()),
    ]);
    let entities = bcif_to_entities(&bcif).unwrap();
    let rna = entities
        .iter()
        .find(|e| e.molecule_type() == MoleculeType::RNA)
        .expect("expected an RNA entity");
    let na = rna.as_nucleic_acid().unwrap();
    assert_eq!(na.residues.len(), 3);
}

#[test]
fn auth_chain_id_visible_on_writeback() {
    let mut rows = Vec::new();
    for chain_label in ["A", "B"] {
        for r in ala_rows(chain_label, 0.0) {
            rows.push(AtomSite {
                auth_asym_id: Some("H"),
                auth_seq_id: Some(if chain_label == "A" { 11 } else { 21 }),
                auth_comp_id: Some("ALA"),
                auth_atom_id: Some(r.label_atom_id),
                ..r
            });
        }
    }
    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_protein_category(),
        atom_site_category(
            &rows,
            &AtomSiteOpts {
                include_auth: true,
                ..AtomSiteOpts::default()
            },
        ),
    ]);
    let entities = bcif_to_entities(&bcif).unwrap();
    let proteins: Vec<_> = entities
        .iter()
        .filter(|e| e.molecule_type() == MoleculeType::Protein)
        .collect();
    assert_eq!(proteins.len(), 2);
    let auth_chains: Vec<Option<u8>> = proteins
        .iter()
        .map(|e| e.as_protein().unwrap().auth_asym_id)
        .collect();
    let first = auth_chains[0].expect("auth_asym_id should be populated");
    assert!(
        auth_chains.iter().all(|c| *c == Some(first)),
        "homodimer chains should share auth byte; got {auth_chains:?}"
    );
    let label_chains: Vec<char> = proteins
        .iter()
        .map(|e| e.as_protein().unwrap().pdb_chain_id as char)
        .collect();
    assert!(label_chains.contains(&'A') && label_chains.contains(&'B'));
}

#[test]
fn single_model_api_returns_first_model() {
    let mut rows = Vec::new();
    for (i, base) in [0.0_f64, 10.0, 20.0].iter().enumerate() {
        for r in ala_rows("A", *base) {
            rows.push(AtomSite {
                model: (i as i32) + 1,
                ..r
            });
        }
    }
    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_protein_category(),
        atom_site_category(&rows, &AtomSiteOpts::default()),
    ]);
    let entities = bcif_to_entities(&bcif).unwrap();
    let n = find_atom_by_name(first_protein(&entities), "N").unwrap();
    assert!(n.position.x.abs() < 0.5, "got x={}", n.position.x);
}

#[test]
fn all_models_returns_three_buckets() {
    let mut rows = Vec::new();
    for (i, base) in [0.0_f64, 10.0, 20.0].iter().enumerate() {
        for r in ala_rows("A", *base) {
            rows.push(AtomSite {
                model: (i as i32) + 1,
                ..r
            });
        }
    }
    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_protein_category(),
        atom_site_category(&rows, &AtomSiteOpts::default()),
    ]);
    let models = bcif_to_all_models(&bcif).unwrap();
    assert_eq!(models.len(), 3);
    for (i, model) in models.iter().enumerate() {
        let n = find_atom_by_name(first_protein(model), "N").unwrap();
        let expected_x = (i as f32) * 10.0;
        assert!(
            (n.position.x - expected_x).abs() < 0.5,
            "model {} expected x={}, got {}",
            i + 1,
            expected_x,
            n.position.x
        );
    }
}

#[test]
fn altloc_a_wins_over_b_by_occupancy() {
    let mut rows = ala_rows("A", 0.0);
    rows.push(AtomSite {
        label_atom_id: "CB",
        label_comp_id: "ALA",
        label_asym_id: "A",
        label_seq_id: 1,
        label_entity_id: "1",
        x: 2.0,
        y: 1.0,
        z: 0.0,
        occupancy: 0.6,
        b_factor: 10.0,
        type_symbol: "C",
        model: 1,
        label_alt_id: Some("A"),
        auth_asym_id: None,
        auth_seq_id: None,
        auth_comp_id: None,
        auth_atom_id: None,
        ins_code: None,
        formal_charge: None,
    });
    rows.push(AtomSite {
        label_atom_id: "CB",
        label_comp_id: "ALA",
        label_asym_id: "A",
        label_seq_id: 1,
        label_entity_id: "1",
        x: 3.0,
        y: 1.0,
        z: 0.0,
        occupancy: 0.4,
        b_factor: 10.0,
        type_symbol: "C",
        model: 1,
        label_alt_id: Some("B"),
        auth_asym_id: None,
        auth_seq_id: None,
        auth_comp_id: None,
        auth_atom_id: None,
        ins_code: None,
        formal_charge: None,
    });
    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_protein_category(),
        atom_site_category(
            &rows,
            &AtomSiteOpts {
                include_alt_id: true,
                ..AtomSiteOpts::default()
            },
        ),
    ]);
    let entities = bcif_to_entities(&bcif).unwrap();
    let cb_atoms: Vec<_> = first_protein(&entities)
        .atom_set()
        .iter()
        .filter(|a| std::str::from_utf8(&a.name).unwrap().trim() == "CB")
        .collect();
    assert_eq!(cb_atoms.len(), 1);
    assert!((cb_atoms[0].position.x - 2.0).abs() < 0.01);
}

#[test]
fn ins_code_disambiguates_inserts() {
    let mut rows = Vec::new();
    for (seq_id, ins) in [(1, None), (2, Some("A")), (2, Some("B"))] {
        for r in ala_rows("A", (seq_id as f64) * 4.0) {
            rows.push(AtomSite {
                label_seq_id: seq_id,
                ins_code: ins,
                ..r
            });
        }
    }
    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_protein_category(),
        atom_site_category(
            &rows,
            &AtomSiteOpts {
                include_ins_code: true,
                ..AtomSiteOpts::default()
            },
        ),
    ]);
    let entities = bcif_to_entities(&bcif).unwrap();
    let protein = first_protein(&entities).as_protein().unwrap();
    assert_eq!(protein.residues.len(), 3);
    let ins_codes: Vec<Option<u8>> =
        protein.residues.iter().map(|r| r.ins_code).collect();
    assert!(ins_codes.contains(&Some(b'A')));
    assert!(ins_codes.contains(&Some(b'B')));
}

#[test]
fn formal_charge_field_populated() {
    let mut rows = ala_rows("A", 0.0);
    rows[0].formal_charge = Some(2);
    rows[1].formal_charge = Some(-1);
    rows[2].formal_charge = Some(1);
    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_protein_category(),
        atom_site_category(
            &rows,
            &AtomSiteOpts {
                include_formal_charge: true,
                ..AtomSiteOpts::default()
            },
        ),
    ]);
    let entities = bcif_to_entities(&bcif).unwrap();
    let charges: Vec<i8> = entities
        .iter()
        .flat_map(|e| e.atom_set().iter().map(|a| a.formal_charge))
        .collect();
    assert!(charges.contains(&2));
    assert!(charges.contains(&-1));
    assert!(charges.contains(&1));
}

#[test]
fn branched_entities_collapse_without_crash() {
    let mut rows = ala_rows("A", 0.0);
    rows.push(AtomSite {
        label_atom_id: "C1",
        label_comp_id: "NAG",
        label_asym_id: "B",
        label_seq_id: 1,
        label_entity_id: "2",
        x: 100.0,
        y: 0.0,
        z: 0.0,
        occupancy: 1.0,
        b_factor: 10.0,
        type_symbol: "C",
        model: 1,
        label_alt_id: None,
        auth_asym_id: None,
        auth_seq_id: None,
        auth_comp_id: None,
        auth_atom_id: None,
        ins_code: None,
        formal_charge: None,
    });
    let entity_cat = Category {
        name: "_entity".into(),
        row_count: 2,
        columns: vec![
            Column {
                name: "id".into(),
                data: ColumnData::Strings(vec!["1".into(), "2".into()]),
                mask: None,
            },
            Column {
                name: "type".into(),
                data: ColumnData::Strings(vec![
                    "polymer".into(),
                    "branched".into(),
                ]),
                mask: None,
            },
        ],
    };
    let bcif = build_single(vec![
        entity_cat,
        entity_poly_protein_category(),
        atom_site_category(&rows, &AtomSiteOpts::default()),
    ]);
    let entities = bcif_to_entities(&bcif).unwrap();
    assert!(entities
        .iter()
        .any(|e| e.molecule_type() == MoleculeType::Protein));
    // NAG is a non-polymer branched residue; it must land somewhere.
    assert!(entities.iter().any(|e| !matches!(
        e.molecule_type(),
        MoleculeType::Protein | MoleculeType::DNA | MoleculeType::RNA
    )));
}

#[test]
fn multi_block_input_refuses_with_clear_message() {
    let bcif = build_bcif(&[
        block_for(vec![
            entity_polymer_category(),
            entity_poly_protein_category(),
            atom_site_category(&ala_rows("A", 0.0), &AtomSiteOpts::default()),
        ]),
        block_for(vec![]),
    ]);
    let err = bcif_to_entities(&bcif).unwrap_err();
    let msg = err.to_string();
    assert!(msg.contains("data blocks"), "msg: {msg}");
}

