#[test]
fn null_mask_present_drops_masked_coord_rows() {
    let mut rows = ala_rows("A", 0.0);
    rows.extend(ala_rows("A", 4.0).into_iter().map(|r| AtomSite {
        label_seq_id: 2,
        ..r
    }));
    let mut coord_mask = vec![0u8; rows.len()];
    // Mask the entire second residue's coordinates.
    for i in 4..8 {
        coord_mask[i] = 1;
    }
    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_protein_category(),
        atom_site_category(
            &rows,
            &AtomSiteOpts {
                coord_masks: Some(coord_mask),
                ..AtomSiteOpts::default()
            },
        ),
    ]);
    let entities = bcif_to_entities(&bcif).unwrap();
    let protein = first_protein(&entities).as_protein().unwrap();
    assert_eq!(
        protein.residues.len(),
        1,
        "masked residue should not appear; got {:?}",
        protein.residues.len()
    );
}

#[test]
fn null_mask_on_occupancy_defaults_to_one() {
    let rows = ala_rows("A", 0.0);
    let occ_mask = vec![1u8; rows.len()];
    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_protein_category(),
        atom_site_category(
            &rows,
            &AtomSiteOpts {
                occupancy_mask: Some(occ_mask),
                ..AtomSiteOpts::default()
            },
        ),
    ]);
    let entities = bcif_to_entities(&bcif).unwrap();
    for a in first_protein(&entities).atom_set() {
        assert!(
            (a.occupancy - 1.0).abs() < 1e-6,
            "occupancy not defaulted: {}",
            a.occupancy
        );
    }
}

#[test]
fn integer_packing_byte4_decodes_correctly() {
    // High-magnitude residue number (>32k) demands byteCount=4 packing.
    // Four atoms share one big seq id so they form a single protein residue.
    let big_seq: i32 = 200_000;
    let mut bytes = Vec::new();
    for _ in 0..4 {
        bytes.extend_from_slice(&big_seq.to_le_bytes());
    }

    let raw_seq = Column {
        name: "label_seq_id".into(),
        data: ColumnData::Raw {
            bytes,
            encoding: vec![
                EncStep::IntegerPacking {
                    byte_count: 4,
                    src_size: 4,
                    is_unsigned: false,
                },
                EncStep::ByteArrayInt32,
            ],
        },
        mask: None,
    };

    let rows = ala_rows("A", 0.0);
    let mut cat = atom_site_category(&rows, &AtomSiteOpts::default());
    cat.columns.retain(|c| c.name != "label_seq_id");
    cat.columns.push(raw_seq);

    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_protein_category(),
        cat,
    ]);
    let entities = bcif_to_entities(&bcif).unwrap();
    let protein = first_protein(&entities).as_protein().unwrap();
    assert_eq!(protein.residues.len(), 1);
    assert_eq!(protein.residues[0].label_seq_id, big_seq);
}

#[test]
fn run_length_bounded_refuses_amplified_input() {
    // Encode a srcSize that exceeds the decoder's MAX_RUN_LENGTH_OUTPUT.
    let crafted_pairs: Vec<i32> = vec![7, i32::MAX];
    let mut packed_bytes = Vec::new();
    for v in &crafted_pairs {
        packed_bytes.extend_from_slice(&v.to_le_bytes());
    }
    let raw_seq = Column {
        name: "label_seq_id".into(),
        data: ColumnData::Raw {
            bytes: packed_bytes,
            encoding: vec![
                EncStep::RunLength {
                    src_size: i32::MAX,
                    src_type: 3,
                },
                EncStep::ByteArrayInt32,
            ],
        },
        mask: None,
    };

    let rows = ala_rows("A", 0.0);
    let mut cat = atom_site_category(&rows, &AtomSiteOpts::default());
    cat.columns.retain(|c| c.name != "label_seq_id");
    cat.columns.push(raw_seq);
    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_protein_category(),
        cat,
    ]);
    let err = bcif_to_entities(&bcif).unwrap_err();
    let msg = err.to_string();
    assert!(
        msg.contains("RunLength") || msg.contains("srcSize"),
        "expected RunLength bound error, got {msg}"
    );
}

#[test]
fn element_falls_back_to_atom_name_when_type_symbol_missing() {
    let rows = ala_rows("A", 0.0);
    let mut cat = atom_site_category(&rows, &AtomSiteOpts::default());
    cat.columns.retain(|c| c.name != "type_symbol");
    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_protein_category(),
        cat,
    ]);
    let entities = bcif_to_entities(&bcif).unwrap();
    let atoms = first_protein(&entities).atom_set();
    assert_eq!(atoms[0].element, Element::N);
    assert_eq!(atoms[1].element, Element::C);
    assert_eq!(atoms[3].element, Element::O);
}

#[test]
fn file_entry_point_roundtrips_through_disk() {
    let bcif = build_single(vec![
        entity_polymer_category(),
        entity_poly_protein_category(),
        atom_site_category(&ala_rows("A", 0.0), &AtomSiteOpts::default()),
    ]);
    let path = std::env::temp_dir().join("molex_bcif_roundtrip.bcif");
    std::fs::write(&path, &bcif).unwrap();
    let entities = bcif_file_to_entities(&path).unwrap();
    let _ = std::fs::remove_file(&path);
    let protein = first_protein(&entities).as_protein().unwrap();
    assert_eq!(protein.residues.len(), 1);
}
